import test from 'node:test';
import assert from 'node:assert/strict';

import { CookieJar } from '../src/cookie-jar.mjs';
import { parseSetCookie } from '../src/set-cookie.mjs';

test('zero is retained as an explicit deletion age', () => {
  assert.equal(parseSetCookie('sid=gone; Max-Age=0').maxAge, 0);
});

test('domain and path matching use label and segment boundaries', () => {
  const jar = new CookieJar();
  jar.store('region=west; Domain=example.test; Path=/docs', 'https://api.example.test/docs');
  assert.deepEqual(jar.cookiesFor('https://badexample.test/docs'), []);
  assert.deepEqual(jar.cookiesFor('https://api.example.test/docset'), []);
  assert.deepEqual(jar.cookiesFor('https://edge.example.test/docs/1'), [
    { name: 'region', value: 'west' }
  ]);
});
